import{b as t,J as r,g as i,j as o}from"./chunks/framework.DVAsBjJ_.js";const u=JSON.parse('{"title":"실행기록 (Activity)","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/activity.md","filePath":"work-manage/activity.md","lastUpdated":1780678209000}'),e={name:"work-manage/activity.md"};function l(n,a,s,h,c,d){return r(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="실행기록-activity" tabindex="-1">실행기록 (Activity) <a class="header-anchor" href="#실행기록-activity" aria-label="Permalink to &quot;실행기록 (Activity)&quot;">​</a></h1><p><strong>실행기록</strong> 페이지는 프로젝트 내에서 발생한 모든 변경 사항과 활동 내역을 시간 순으로 확인할 수 있는 &#39;프로젝트 히스토리&#39; 화면입니다. 누가, 언제, 어떤 업무를 수행했는지 한눈에 파악할 수 있습니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>실행기록은 프로젝트의 살아있는 기록부와 같습니다. 업무의 생성, 수정, 댓글 작성뿐만 아니라 공지사항이나 문서의 업데이트 내역까지 날짜별로 정리되어 표시됩니다. 기본적으로 최근 10일간의 기록을 먼저 보여줍니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📅-기간별-기록-조회-및-이동" tabindex="-1">📅 기간별 기록 조회 및 이동 <a class="header-anchor" href="#📅-기간별-기록-조회-및-이동" aria-label="Permalink to &quot;📅 기간별 기록 조회 및 이동&quot;">​</a></h3><ul><li><strong>기간 확인</strong>: 목록 상단에 표시된 날짜 범위를 통해 현재 보고 있는 기록의 기간을 확인할 수 있습니다.</li><li><strong>날짜 이동</strong>: 목록 하단의 <strong>[« 뒤로]</strong> 버튼은 10일 이전의 기록으로, <strong>[다음 »]</strong> 버튼은 10일 이후의 기록으로 이동합니다.</li><li><strong>특정 날짜 지정</strong>: 우측 설정창의 &#39;10일 기록&#39; 달력 아이콘을 클릭하여 특정 날짜를 선택하면, 해당 날짜를 기준으로 과거 10일간의 기록을 즉시 불러옵니다.</li></ul><h3 id="👥-사용자별-활동-필터링" tabindex="-1">👥 사용자별 활동 필터링 <a class="header-anchor" href="#👥-사용자별-활동-필터링" aria-label="Permalink to &quot;👥 사용자별 활동 필터링&quot;">​</a></h3><ul><li>특정 팀원의 활동만 모아보고 싶을 때 우측 설정창의 <strong>[사용자]</strong> 필터를 사용합니다.</li><li>본인의 활동 내역만 확인하려면 목록에서 **[&lt;&lt; 나 &gt;&gt;]**를 선택하고 &#39;적용&#39; 버튼을 클릭하세요.</li></ul><h3 id="🗂️-활동-유형별-필터링" tabindex="-1">🗂️ 활동 유형별 필터링 <a class="header-anchor" href="#🗂️-활동-유형별-필터링" aria-label="Permalink to &quot;🗂️ 활동 유형별 필터링&quot;">​</a></h3><p>보고 싶은 활동의 종류만 선택하여 목록을 간소화할 수 있습니다.</p><ul><li><strong>업무</strong>: 업무 생성, 상태 변경, 댓글 작성 등 이슈 관련 모든 활동.</li><li><strong>공지</strong>: 새로운 공지사항 등록 및 수정 내역.</li><li><strong>문서</strong>: 관련 문서 자료의 업로드 및 관리 내역.</li><li><strong>글</strong>: 게시판이나 포럼 등에 작성된 게시글 내역.</li></ul><h3 id="🌲-하위-프로젝트-포함" tabindex="-1">🌲 하위 프로젝트 포함 <a class="header-anchor" href="#🌲-하위-프로젝트-포함" aria-label="Permalink to &quot;🌲 하위 프로젝트 포함&quot;">​</a></h3><ul><li>현재 프로젝트에 포함된 하위 프로젝트들의 활동까지 함께 보고 싶다면 <strong>[하위 프로젝트]</strong> 체크박스를 선택하세요. 대규모 프로젝트의 전체 흐름을 파악할 때 유용합니다.</li></ul><h2 id="_3-이용-팁" tabindex="-1">3. 이용 팁 <a class="header-anchor" href="#_3-이용-팁" aria-label="Permalink to &quot;3. 이용 팁&quot;">​</a></h2><ul><li><strong>상세 내용 바로가기</strong>: 활동 기록에 표시된 업무 제목이나 게시글 제목을 클릭하면 해당 항목의 상세 페이지로 직접 이동하여 자세한 내용을 확인할 수 있습니다.</li><li><strong>히스토리 추적</strong>: 특정 업무의 상태가 왜 변경되었는지 궁금할 때 해당 날짜의 실행기록을 찾아보면 전후 맥락을 파악하는 데 도움이 됩니다.</li></ul>',16)])])}const _=t(e,[["render",l]]);export{u as __pageData,_ as default};
